// Garde les pièces jointes qui ont un nom ET une taille > 0.
// Élimine les binaires vides / fantômes (ex: f_diplome non fourni) qui font planter Gmail.
const items = $input.all();
for (const item of items) {
  const binaries = item.binary || {};
  const cleaned = {};
  for (const key of Object.keys(binaries)) {
    const b = binaries[key];
    const size = typeof b.fileSize === 'number' ? b.fileSize : parseFloat(String(b.fileSize || '0'));
    if (b.fileName && b.fileName.trim() !== '' && size > 0) {
      cleaned[key] = b;
    }
  }
  item.binary = cleaned;
}
return items;
